import axios from "axios";

// Create axios instance
const api = axios.create({
  baseURL: "http://localhost:5000/api",
  headers: { "Content-Type": "application/json" },
});

// Add JWT token to all requests if present
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem("nfxtoken");
    if (token) config.headers.Authorization = `Bearer ${token}`;
    return config;
  },
  (error) => Promise.reject(error)
);

// Optionally: handle unauthorized responses
api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response && (error.response.status === 401 || error.response.status === 403)) {
      localStorage.removeItem("nfxtoken");
      // Optionally, redirect to login: window.location.href = "/login";
    }
    return Promise.reject(error);
  }
);

// Login user
export const loginUser = async ({ email, password }) => {
  const response = await api.post("/auth/login", { email, password });
  if (response.data && response.data.token) {
    localStorage.setItem("nfxtoken", response.data.token);
  }
  return response.data;
};

// Signup user
export const signupUser = async ({ name, email, password }) => {
  const response = await api.post("/auth/register", { name, email, password });
  return response.data;
};

// Create a vehicle
export const createVehicle = async (payload) => {
  const response = await api.post("/vehicles", payload);
  return response.data;
};

// List vehicles
export const listVehicles = async () => {
  const response = await api.get("/vehicles");
  return response.data;
};

export default api;
